15	AffixSegmentor::AffixSegmentor(const Ticket& ticket)
16	    : Segmentor(ticket), tag_("abc") {
17	  if (!ticket.schema)
18	    return;
19	  if (Config* config = ticket.schema->config()) {
20	    config->GetString(name_space_ + "/tag", &tag_);
21	    config->GetString(name_space_ + "/prefix", &prefix_);
22	    config->GetString(name_space_ + "/suffix", &suffix_);
23	    config->GetString(name_space_ + "/tips", &tips_);
24	    config->GetString(name_space_ + "/closing_tips", &closing_tips_);
25	    if (auto extra_tags = config->GetList(name_space_ + "/extra_tags")) {
26	      for (size_t i = 0; i < extra_tags->size(); ++i) {
27	        if (auto value = extra_tags->GetValueAt(i)) {
28	          extra_tags_.insert(value->str());
29	        }
30	      }
31	    }
32	  }
33	}
34	
35	bool AffixSegmentor::Proceed(Segmentation* segmentation) {
36	  if (segmentation->empty())
37	    return true;
38	  if (!segmentation->back().HasTag(tag_)) {
39	    if (segmentation->size() >= 2) {
40	      Segment& previous_segment(*(segmentation->rbegin() + 1));
41	      if (previous_segment.HasTag("partial") && previous_segment.HasTag(tag_)) {
42	        // the remaining part of a partial selection should inherit the tag
43	        segmentation->back().tags.insert(tag_);
44	        // without adding new tag "abc"
45	        if (!previous_segment.HasTag("abc")) {
46	          segmentation->back().tags.erase("abc");
47	        }
48	      }
49	    }
50	    return true;
51	  }
52	  size_t j = segmentation->GetCurrentStartPosition();
53	  size_t k = segmentation->GetCurrentEndPosition();
54	  string active_input(segmentation->input().substr(j, k - j));
55	  if (prefix_.empty() || !boost::starts_with(active_input, prefix_)) {
56	    return true;
57	  }
58	  DLOG(INFO) << "affix_segmentor: " << active_input;
59	  DLOG(INFO) << "segmentation: " << *segmentation;
60	  // just prefix
61	  if (active_input.length() == prefix_.length()) {
62	    Segment& prefix_segment(segmentation->back());
63	    prefix_segment.tags.erase(tag_);
64	    prefix_segment.prompt = tips_;
65	    prefix_segment.tags.insert(tag_ + "_prefix");
66	    DLOG(INFO) << "prefix: " << *segmentation;
67	    // continue this round
68	    return true;
69	  }
70	  // prefix + code
71	  active_input.erase(0, prefix_.length());
72	  Segment prefix_segment(j, j + prefix_.length());
73	  prefix_segment.status = Segment::kGuess;
74	  prefix_segment.prompt = tips_;
75	  prefix_segment.tags.insert(tag_ + "_prefix");
76	  prefix_segment.tags.insert("phony");  // do not commit raw input
77	  segmentation->pop_back();
78	  segmentation->Forward();
79	  segmentation->AddSegment(prefix_segment);
80	  j += prefix_.length();
81	  Segment code_segment(j, k);
82	  code_segment.tags.insert(tag_);
83	  for (const string& tag : extra_tags_) {
84	    code_segment.tags.insert(tag);
85	  }
86	  segmentation->Forward();
87	  segmentation->AddSegment(code_segment);
88	  DLOG(INFO) << "prefix+code: " << *segmentation;
89	  // has suffix?
90	  if (!suffix_.empty() && boost::ends_with(active_input, suffix_)) {
91	    k -= suffix_.length();
92	    if (k == segmentation->back().start) {
93	      segmentation->pop_back();  // code is empty
94	    } else {
95	      segmentation->back().end = k;
96	    }
97	    Segment suffix_segment(k, k + suffix_.length());
98	    suffix_segment.status = Segment::kGuess;
99	    suffix_segment.prompt = closing_tips_.empty() ? tips_ : closing_tips_;
100	    suffix_segment.tags.insert(tag_ + "_suffix");
101	    suffix_segment.tags.insert("phony");  // do not commit raw input
102	    segmentation->Forward();
103	    segmentation->AddSegment(suffix_segment);
104	    DLOG(INFO) << "prefix+suffix: " << *segmentation;
105	  }
106	  // exclusive
107	  return false;
108	}
