18	static void load_patterns(RecognizerPatterns* patterns, an<ConfigMap> map) {
19	  if (!patterns || !map)
20	    return;
21	  for (auto it = map->begin(); it != map->end(); ++it) {
22	    auto value = As<ConfigValue>(it->second);
23	    if (!value)
24	      continue;
25	    try {
26	      boost::regex pattern(value->str());
27	      (*patterns)[it->first] = pattern;
28	    } catch (boost::regex_error& e) {
29	      LOG(ERROR) << "error parsing pattern /" << value->str()
30	                 << "/: " << e.what();
31	    }
32	  }
33	}
34	
35	void RecognizerPatterns::LoadConfig(Config* config, const string& name_space) {
36	  load_patterns(this, config->GetMap(name_space + "/patterns"));
37	}
38	
39	RecognizerMatch RecognizerPatterns::GetMatch(
40	    const string& input,
41	    const Segmentation& segmentation) const {
42	  size_t j = segmentation.GetCurrentEndPosition();
43	  size_t k = segmentation.GetConfirmedPosition();
44	  string active_input = input.substr(k);
45	  DLOG(INFO) << "matching active input '" << active_input << "' at pos " << k;
46	  for (const auto& v : *this) {
47	    boost::smatch m;
48	    if (boost::regex_search(active_input, m, v.second)) {
49	      size_t start = k + m.position();
50	      size_t end = start + m.length();
51	      if (end != input.length())
52	        continue;
53	      if (start == j) {
54	        DLOG(INFO) << "input [" << start << ", " << end << ") '" << m.str()
55	                   << "' matches pattern: " << v.first;
56	        return {v.first, start, end};
57	      }
58	      for (const Segment& seg : segmentation) {
59	        if (start < seg.start)
60	          break;
61	        if (start == seg.start) {
62	          DLOG(INFO) << "input [" << start << ", " << end << ") '" << m.str()
63	                     << "' matches pattern: " << v.first;
64	          return {v.first, start, end};
65	        }
66	      }
67	    }
68	  }
69	  return RecognizerMatch();
70	}
71	
72	Recognizer::Recognizer(const Ticket& ticket) : Processor(ticket) {
73	  if (!ticket.schema)
